{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations based on tree structures. This involves analyzing tree topology, identifying mergeable nodes, and determining the order of operations.",
  "helpers": [
    {
      "label": "tree_topology_analyzer",
      "instructions": "Represent the initial and final trees using adjacency lists or parent-child mappings. Identify the degree of each node in both trees and determine which nodes are 'internal' (have children) and which are 'leaves'."
    },
    {
      "label": "merge_operation_identifier",
      "instructions": "Identify the specific pairs of sibling nodes that must have been merged to transform the initial tree into the final tree. A merge operation reduces the number of children of a parent node by combining two siblings into one."
    },
    {
      "label": "dependency_graph_builder",
      "instructions": "Construct a directed acyclic graph (DAG) where each node represents a merge operation. An edge exists from operation A to operation B if the result of operation A is a node that must be part of operation B (i.e., B merges a node created by A with another sibling)."
    },
    {
      "label": "topological_sorter",
      "instructions": "Perform a topological sort on the dependency graph constructed by the previous helper to find a valid linear sequence of merge operations that respects all structural dependencies."
    }
  ],
  "synthesis_brief": "Combine the topological sort of the merge operations to produce the final sequence. Verify that the sequence of operations, when applied to the initial tree, results in the final tree structure."
}
```

